\"\",\"topics\":null,\"updateTime\":\"2026-07-16T10:00:50+08:00\"},{\"categoryId\":4,\"categoryName\":\"дёӯй—ҙд»¶\",\"content\":\"\",\"createTime\":\"2026-07-05T01:43:01+08:00\",\"description\":\"иҝҷзҜҮж–Үз« жҳҜеҶҷз»ҷеҲҡжҺҘи§ҰеҗҺз«ҜејҖеҸ‘зҡ„еҗҢеӯҰпјҢжҲ–иҖ…жӯЈеңЁеҮҶеӨҮе®һд№ йқўиҜ•зҡ„еӯҰејҹеӯҰеҰ№гҖӮеҫҲеӨҡе…¬еҸёйқўиҜ•йғҪдјҡй—®\\\"дҪ д»¬йЎ№зӣ®жҖҺд№ҲйғЁзҪІзҡ„пјҹ\\\"пјҢJenkinsе°ұжҳҜзӯ”жЎҲд№ӢдёҖгҖӮиҜ»е®ҢиҝҷзҜҮпјҢдҪ иғҪжҗһжҮӮJenkinsеҲ°еә•жҳҜе№Іеҳӣзҡ„гҖҒдёәд»Җд№ҲиҰҒз”ЁгҖҒд»ҘеҸҠжҖҺд№Ҳе…Ҙй—ЁгҖӮе»әи®®ж”¶и—ҸпјҢиҪ¬еҸ‘з»ҷеҗҢж ·еңЁиҮӘеӯҰзҡ„е®ӨеҸӢгҖӮ\",\"id\":55,\"isPublished\":true,\"isTop\":false,\"likeNum\":0,\"publishTime\":null,\"readNum\":4,\"shareNum\":0,\"slug\":\"article-55\",\"tags\":[{\"id\":5,\"name\":\"Spring\"},{\"id\":6,\"name\":\"SpringBoot\"}],\"title\":\"JenkinsжҳҜд»Җд№Ҳпјҹд»Һ0ејҖе§ӢжҗһжҮӮжҢҒз»ӯйӣҶжҲҗдёҺиҮӘеҠЁеҢ–йғЁзҪІ\",\"titleImage\":\"\",\"topics\":null,\"updateTime\":\"2026-07-08T20:08:47+08:00\"},{\"categoryId\":8,\"categoryName\":\"дәәе·ҘжҷәиғҪ\",\"content\":\"\",\"createTime\":\"2026-07-03T06:17:59+08:00\",\"description\":\"иҝҷзҜҮж–Үз« еҶҷз»ҷжғіеӯҰ AI ејҖеҸ‘дҪҶеҸҲдёҚжғіиҪ¬ Python зҡ„ Java еҗҢеӯҰгҖӮжҲ‘ 2024 е№ҙеҲқејҖе§Ӣз”Ё Spring AIпјҢеёҰиҝҮеҮ дёӘеӯҰз”ҹз”Ёе®ғеҒҡжҜ•и®ҫгҖӮзңӢе®ҢдҪ иғҪеҲӨж–ӯиҝҷдёӘжЎҶжһ¶еҖјдёҚеҖјеҫ—жҠ•е…Ҙж—¶й—ҙгҖӮ\",\"id\":54,\"isPublished\":true,\"isTop\":false,\"likeNum\":0,\"publishTime\":null,\"readNum\":9,\"shareNum\":0,\"slug\":\"article-54\",\"tags\":[{\"id\":6,\"name\":\"SpringBoot\"},{\"id\":14,\"name\":\"дәәе·ҘжҷәиғҪ\"}],\"title\":\"Spring AI еҲ°еә•иғҪдёҚиғҪи®© Java зЁӢеәҸе‘ҳзҺ©иҪ¬еӨ§жЁЎеһӢпјҹжҲ‘з”Ёе®Ңд№ӢеҗҺзҡ„зңҹе®һж„ҹеҸ—\",\"titleImage\":\"\",\"topics\":null,\"updateTime\":\"2026-07-08T20:10:37+08:00\"},{\"categoryId\":8,\"categoryName\":\"дәәе·ҘжҷәиғҪ\",\"content\":\"\",\"createTime\":\"2026-07-02T05:38:56+08:00\",\"description\":\"Spring AI е»¶з»ӯдәҶиҝҷдёӘжҖқи·ҜгҖӮе®ғеҒҡзҡ„дәӢжғ…жҳҜпјҡдҪ жҠҠ AI зӣёе…ізҡ„жңҚеҠЎпјҲеӨ§жЁЎеһӢгҖҒеҗ‘йҮҸж•°жҚ®еә“гҖҒж–ҮжЎЈи§ЈжһҗпјүжҺҘе…ҘиҝӣжқҘпјҢSpring AI её®дҪ е°ҒиЈ…еҘҪпјҢдҪ еҸӘйңҖиҰҒеҶҷдёҖеҘ—д»Јз ҒпјҢе°ұи