¬\\n еӨҡдәәеҚҸдҪңдёҚеҶІзӘҒ\\n\\n GitдёҺSVNзҡ„еҢәеҲ«\\n GitжҳҜеҲҶеёғејҸпјҢжҜҸдәәйғҪжңүе®Ңж•ҙд»“еә“\\n SVNжҳҜйӣҶдёӯејҸпјҢеҝ…йЎ»иҒ”зҪ‘ж“ҚдҪң\\n Gitжң¬ең°ж“ҚдҪңйҖҹеәҰеҝ«\\n\\n зҺҜеўғй…ҚзҪ®\\n е®үиЈ…Git\\n Windowsе®ҳзҪ‘дёӢиҪҪе®ү...\",\"id\":59,\"isPublished\":true,\"isTop\":false,\"likeNum\":0,\"publishTime\":null,\"readNum\":2,\"shareNum\":0,\"slug\":\"\",\"tags\":[{\"id\":1,\"name\":\"Java\"}],\"title\":\"GitзүҲжң¬жҺ§еҲ¶е®һжҲҳж•ҷзЁӢ\",\"titleImage\":\"\",\"topics\":null,\"updateTime\":\"2026-07-16T13:09:37+08:00\"},{\"categoryId\":8,\"categoryName\":\"дәәе·ҘжҷәиғҪ\",\"content\":\"\",\"createTime\":\"2026-07-05T10:50:04+08:00\",\"description\":\"иҝҷзҜҮж–Үз« жҳҜдёәеҲҡжҺҘи§Ұ RAGпјҲжЈҖзҙўеўһејәз”ҹжҲҗпјүзҡ„еҗҢеӯҰеҶҷзҡ„гҖӮжҲ‘еңЁеҹ№и®ӯеӯҰз”ҹеҒҡ RAG йЎ№зӣ®ж—¶пјҢеҸ‘зҺ°еҫҲеӨҡдәәеҚЎеңЁ\\\"еҗ‘йҮҸжЁЎеһӢ\\\"иҝҷдёҖжӯҘвҖ”вҖ”дёҚзҹҘйҒ“йҖүе“ӘдёӘпјҢд№ҹдёҚзҹҘйҒ“дёәд»Җд№ҲйҖүгҖӮиҜ»е®ҢиҝҷзҜҮпјҢдҪ дјҡжҳҺзҷҪеөҢе…ҘжЁЎеһӢеҲ°еә•жҳҜе№Ід»Җд№Ҳзҡ„пјҢд»ҘеҸҠ bge-m3 е’Ң nomic-embed-text еҗ„иҮӘйҖӮеҗҲд»Җд№ҲеңәжҷҜгҖӮе»әи®®ж”¶и—ҸпјҢиҪ¬еҸ‘з»ҷжӯЈеңЁеҒҡжҜ•и®ҫзҡ„е®ӨеҸӢгҖӮ\",\"id\":56,\"isPublished\":true,\"isTop\":false,\"likeNum\":1,\"publishTime\":null,\"readNum\":16,\"shareNum\":0,\"slug\":\"article-56\",\"tags\":[{\"id\":14,\"name\":\"дәәе·ҘжҷәиғҪ\"}],\"title\":\"д»Җд№ҲжҳҜеөҢе…ҘжЁЎеһӢпјҹbge-m3 е’Ң nomic-embed-text еҲ°еә•жңүе•ҘеҢәеҲ«пјҹ\",\"titleImage\":\"\",\"topics\":null,\"updateTime\":\"2026-07-16T10:00:50+08:00\"},{\"categoryId\":4,\"categoryName\":\"дёӯй—ҙд»¶\",\"content\":\"\",\"createTime\":\"2026-07-05T01:43:01+08:00\",\"description\":\"иҝҷзҜҮж–Үз« жҳҜеҶҷз»ҷеҲҡжҺҘи§ҰеҗҺз«ҜејҖеҸ‘зҡ„еҗҢеӯҰпјҢжҲ–иҖ…жӯЈеңЁеҮҶеӨҮе®һд№ йқўиҜ•зҡ„еӯҰејҹеӯҰеҰ№гҖӮеҫҲеӨҡе…¬еҸёйқўиҜ•йғҪдјҡй—®\\\"дҪ д»¬йЎ№зӣ®жҖҺд№ҲйғЁзҪІзҡ„пјҹ\\\"пјҢJenkinsе°ұжҳҜзӯ”жЎҲд№ӢдёҖгҖӮиҜ»е®ҢиҝҷзҜҮпјҢдҪ иғҪжҗһжҮӮJenkinsеҲ°еә•жҳҜе№Іеҳӣзҡ„гҖҒдёәд»Җд№ҲиҰҒз”ЁгҖҒд»ҘеҸҠжҖҺд№Ҳе…Ҙй—ЁгҖӮе»әи®®ж”¶и—ҸпјҢиҪ¬еҸ‘з»ҷеҗҢж ·еңЁиҮӘеӯҰзҡ„е®ӨеҸӢгҖӮ\",\"id\":55,\"isPublished\":true,\"isTop\":false,\"likeNum\":0,\"publishTime\":null,\"readNum\":4,\"shareNum\":0,\"slug\":\"arti