 RAG йЎ№зӣ®ж—¶пјҢеҸ‘зҺ°еҫҲеӨҡдәәеҚЎеңЁ\\\"еҗ‘йҮҸжЁЎеһӢ\\\"иҝҷдёҖжӯҘвҖ”вҖ”дёҚзҹҘйҒ“йҖүе“ӘдёӘпјҢд№ҹдёҚзҹҘйҒ“дёәд»Җд№ҲйҖүгҖӮиҜ»е®ҢиҝҷзҜҮпјҢдҪ дјҡжҳҺзҷҪеөҢе…ҘжЁЎеһӢеҲ°еә•жҳҜе№Ід»Җд№Ҳзҡ„пјҢд»ҘеҸҠ bge-m3 е’Ң nomic-embed-text еҗ„иҮӘйҖӮеҗҲд»Җд№ҲеңәжҷҜгҖӮе»әи®®ж”¶и—ҸпјҢиҪ¬еҸ‘з»ҷжӯЈеңЁеҒҡжҜ•и®ҫзҡ„е®ӨеҸӢгҖӮ\",\"id\":56,\"isPublished\":true,\"isTop\":false,\"likeNum\":1,\"publishTime\":null,\"readNum\":16,\"shareNum\":0,\"slug\":\"article-56\",\"tags\":[{\"id\":14,\"name\":\"дәәе·ҘжҷәиғҪ\"}],\"title\":\"д»Җд№ҲжҳҜеөҢе…ҘжЁЎеһӢпјҹbge-m3 е’Ң nomic-embed-text еҲ°еә•жңүе•ҘеҢәеҲ«пјҹ\",\"titleImage\":\"\",\"topics\":null,\"updateTime\":\"2026-07-16T10:00:50+08:00\"},{\"categoryId\":4,\"categoryName\":\"дёӯй—ҙд»¶\",\"content\":\"\",\"createTime\":\"2026-07-05T01:43:01+08:00\",\"description\":\"иҝҷзҜҮж–Үз« жҳҜеҶҷз»ҷеҲҡжҺҘи§ҰеҗҺз«ҜејҖеҸ‘зҡ„еҗҢеӯҰпјҢжҲ–иҖ…жӯЈеңЁеҮҶеӨҮе®һд№ йқўиҜ•зҡ„еӯҰејҹеӯҰеҰ№гҖӮеҫҲеӨҡе…¬еҸёйқўиҜ•йғҪдјҡй—®\\\"дҪ д»¬йЎ№зӣ®жҖҺд№ҲйғЁзҪІзҡ„пјҹ\\\"пјҢJenkinsе°ұжҳҜзӯ”жЎҲд№ӢдёҖгҖӮиҜ»е®ҢиҝҷзҜҮпјҢдҪ иғҪжҗһжҮӮJenkinsеҲ°еә•жҳҜе№Іеҳӣзҡ„гҖҒдёәд»Җд№ҲиҰҒз”ЁгҖҒд»ҘеҸҠжҖҺд№Ҳе…Ҙй—ЁгҖӮе»әи®®ж”¶и—ҸпјҢиҪ¬еҸ‘з»ҷеҗҢж ·еңЁиҮӘеӯҰзҡ„е®ӨеҸӢгҖӮ\",\"id\":55,\"isPublished\":true,\"isTop\":false,\"likeNum\":0,\"publishTime\":null,\"readNum\":4,\"shareNum\":0,\"slug\":\"article-55\",\"tags\":[{\"id\":5,\"name\":\"Spring\"},{\"id\":6,\"name\":\"SpringBoot\"}],\"title\":\"JenkinsжҳҜд»Җд№Ҳпјҹд»Һ0ејҖе§ӢжҗһжҮӮжҢҒз»ӯйӣҶжҲҗдёҺиҮӘеҠЁеҢ–йғЁзҪІ\",\"titleImage\":\"\",\"topics\":null,\"updateTime\":\"2026-07-08T20:08:47+08:00\"},{\"categoryId\":8,\"categoryName\":\"дәәе·ҘжҷәиғҪ\",\"content\":\"\",\"createTime\":\"2026-07-03T06:17:59+08:00\",\"description\":\"иҝҷзҜҮж–Үз« еҶҷз»ҷжғіеӯҰ AI ејҖеҸ‘дҪҶеҸҲдёҚжғіиҪ¬ Python зҡ„ Java еҗҢеӯҰгҖӮжҲ‘ 2024 е№ҙеҲқејҖе§Ӣз”Ё Spring AIпјҢеёҰиҝҮеҮ дёӘеӯҰз”ҹз”Ёе®ғеҒҡжҜ•и®ҫгҖӮзңӢе®ҢдҪ иғҪеҲӨж–ӯиҝҷдёӘжЎҶжһ¶еҖјдёҚеҖјеҫ—жҠ•е…Ҙж—¶й—ҙгҖӮ\",\"id\":54,\"isPublished\":true,\"isTop\":false,\"likeNum\":0,\"publishTime\":null,\"readNum\":9,\"shareNum\":0,\"slug\":\"article-54\",\"tags\":[{\"id\":6,\