INSERT INTO `t_article_content` VALUES (1,1,'# йқўеҗ‘еҜ№иұЎдёүеӨ§зү№еҫҒ\n## 1. е°ҒиЈ…\nе°ҒиЈ…жҳҜе°ҶеҜ№иұЎзҡ„еұһжҖ§е’Ңе®һзҺ°з»ҶиҠӮйҡҗи—Ҹиө·жқҘпјҢд»…еҜ№еӨ–жҡҙйңІе…¬е…ұжҺҘеҸЈгҖӮйҖҡиҝҮprivateдҝ®йҘ°еұһжҖ§пјҢжҸҗдҫӣpublicзҡ„getter/setterж–№жі•и®ҝй—®гҖӮ\n```java\npublic class Car {\n    private String name;\n    public String getName() { return this.name; }\n    public void setName(String name) { this.name = name; }\n}\n```\n\n## 2. з»§жүҝ\nз»§жүҝдҪҝз”Ёextendsе…ій”®еӯ—пјҢеӯҗзұ»еҸҜд»ҘеӨҚз”ЁзҲ¶зұ»зҡ„еұһжҖ§е’Ңж–№жі•гҖӮJavaеҸӘж”ҜжҢҒеҚ•з»§жүҝгҖӮ\n```java\npublic class Bus extends Car {\n    public String brand;\n}\n```\n\n## 3. еӨҡжҖҒ\nеӨҡжҖҒжҳҜжҢҮеҗҢдёҖдёӘж–№жі•и°ғз”ЁпјҢз”ұдәҺеҜ№иұЎдёҚеҗҢеҸҜиғҪдјҡжңүдёҚеҗҢзҡ„иЎҢдёәгҖӮ\n```java\nCar car = new Bus(); // зҲ¶зұ»еј•з”ЁжҢҮеҗ‘еӯҗзұ»еҜ№иұЎ\n```\n\n# JDKгҖҒJREгҖҒJVMзҡ„еҢәеҲ«\n- **JDK**пјҡJavaејҖеҸ‘е·Ҙе…·еҢ…пјҢеҢ…еҗ«JREгҖҒејҖеҸ‘е·Ҙе…·е’ҢеҹәзЎҖзұ»еә“гҖӮ\n- **JRE**пјҡJavaиҝҗиЎҢзҺҜеўғпјҢеҢ…еҗ«JVMе’Ңж ёеҝғзұ»еә“гҖӮ\n- **JVM**пјҡJavaиҷҡжӢҹжңәпјҢжҳҜJavaе®һзҺ°и·Ёе№іеҸ°зҡ„ж ёеҝғгҖӮ','2026-06-13 23:43:32','2026-06-15 17:38:21','admin','admin'),(2,2,'# Stringзҡ„дёҚеҸҜеҸҳжҖ§\nStringзұ»иў«finalдҝ®йҘ°пјҢеҜ№иұЎдёҖж—ҰеҲӣе»әеҶ…е®№дёҚеҸҜдҝ®ж”№пјҢйҮҚж–°иөӢеҖјдёҚдјҡдҝ®ж”№еҺҹеӯ—з¬ҰдёІпјҢиҖҢжҳҜз”ҹжҲҗе…Ёж–°еӯ—з¬ҰдёІеҜ№иұЎгҖӮ\n```java\nString x = \"123\";\nx = \"234\"; // еҺҹ\"123\"еҜ№иұЎдёҚеҸҳпјҢеҲӣе»әж–°еҜ№иұЎ\"234\"\n```\n\n## StringгҖҒStringBufferгҖҒStringBuilderдёүиҖ…еҢәеҲ«\n- **String**пјҡдёҚеҸҜеҸҳеёёйҮҸпјҢзәҝзЁӢе®үе…Ёпјӣйў‘з№ҒжӢјжҺҘдјҡдә§з”ҹеӨ§йҮҸдёҙж—¶еҜ№иұЎпјҢйҖӮеҗҲе°‘йҮҸеӯ—з¬ҰдёІж“ҚдҪң\n- **StringBuffer**пјҡеҸҜеҸҳеӯ—з¬Ұе®№еҷЁпјҢж–№жі•еҠ `synchronized`еҗҢжӯҘй”ҒпјҢзәҝзЁӢе®үе…ЁпјӣйҖӮеҗҲеӨҡзәҝзЁӢдёӢеӨ§йҮҸеӯ—з¬ҰдёІжӢјжҺҘ\n- **StringBuilder**пјҡеҸҜеҸҳеӯ—з¬Ұе®№еҷЁпјҢж— еҗҢжӯҘй”ҒпјҢжҖ§иғҪжӣҙй«ҳпјӣеҚ•зәҝзЁӢеңәжҷҜеӨ§йҮҸжӢјжҺҘйҰ–йҖү\n\n## йқўиҜ•й«ҳйў‘зңҹйўҳ\n1. `String s = new String(\"xyz\");` еҲӣе»әеҮ дёӘеҜ№иұЎпјҹ\nдёӨдёӘпјҡеёёйҮҸжұ дёӯз”ҹжҲҗ\"xyz\"еӯ—з¬ҰдёІеёёйҮҸпјҢе ҶеҶ…еӯҳйҖҡиҝҮnewеҲӣе»әStringе®һдҫӢеҜ№иұЎгҖӮ\n\n2.\n```java\nString M = \"ab\";\nString N = \"a\"+\"b\";\nSystem.out.println(M == N);\n```\nиҫ“еҮә `true`пјӣзј–иҜ‘жңҹеёёйҮҸеӯ—з¬ҰдёІжӢјжҺҘдјҡиў«зј–иҜ‘еҷЁдјҳеҢ–дёә\"ab\"пјҢдәҢиҖ…жҢҮеҗ‘еёёйҮҸжұ еҗҢдёҖдёӘеҜ№иұЎгҖӮ','2026-06-13 23:43:32','2026-06-15 17:23:22','admin','admin'),(3,3,'# try-catch-finally жү§иЎҢйЎәеәҸ\nж— ејӮеёёжөҒзЁӢпјҡtry д»Јз Ғеқ—жү§иЎҢ вҶ’ finally жү§иЎҢ\nеҸ‘з”ҹејӮеёёжөҒзЁӢпјҡtry жҠӣеҮәејӮеёё вҶ’ catch жҚ•иҺ·еӨ„зҗҶејӮеёё вҶ’ finally еҝ…е®ҡжү§иЎҢ\n\nе…ій”®зү№жҖ§пјҡ\n`return` иЎЁиҫҫејҸдјҡе…Ҳи®Ўз®—еҮәз»“жһңе№¶зј“еӯҳпјҢйҡҸеҗҺжү§иЎҢ finally д»Јз Ғеқ—пјҢfinally жү§иЎҢе®ҢжҜ•еҗҺеҶҚиҝ”еӣһзј“еӯҳеҘҪзҡ„з»“жһңгҖӮ\nжіЁж„ҸпјҡеҰӮжһңиҝ”еӣһеҖјжҳҜеҹәжң¬ж•°жҚ®зұ»еһӢгҖҒдёҚеҸҜеҸҳеҜ№иұЎпјҲStringзӯүпјүпјҢеңЁfinallyдёӯеҜ№еҸҳйҮҸдҝ®ж”№пјҢдёҚдјҡж”№еҸҳжңҖз»Ҳreturnиҝ”еӣһзҡ„еҖјгҖӮ\n\n# и®ҫи®ЎжЁЎејҸ\n## еҚ•дҫӢжЁЎејҸдёүз§Қе®һзҺ°\n1. **йҘҝжұүејҸ**пјҡзұ»еҠ иҪҪж—¶зӣҙжҺҘе®һдҫӢеҢ–пјҢеӨ©з„¶зәҝзЁӢе®үе…ЁпјҢзјәзӮ№жҳҜзЁӢеәҸеҗҜеҠЁе°ұеҚ з”ЁеҶ…еӯҳгҖӮ\n2. **жҮ’жұүејҸ**пјҡдҪҝз”Ёж—¶жүҚеҲӣе»әе®һдҫӢпјҢе»¶иҝҹеҠ иҪҪпјӣж— еҗҢжӯҘй”ҒпјҢеӨҡзәҝзЁӢе№¶еҸ‘еңәжҷҜзәҝзЁӢдёҚе®үе…ЁгҖӮ\n3. **еҸҢйҮҚжЈҖжҹҘй”ҒпјҲDCLпјү**пјҡе»¶иҝҹеҠ иҪҪгҖҒзәҝзЁӢе®үе…ЁпјҢдҫқйқ  `volatile` йҳІжӯўжҢҮд»ӨйҮҚжҺ’ + `synchronized` еҗҢжӯҘй”Ғе®һзҺ°гҖӮ\n\n## SpringжЎҶжһ¶дёӯеёёи§Ғи®ҫи®ЎжЁЎејҸ\n- **еҚ•дҫӢжЁЎејҸ**пјҡIoCе®№еҷЁдёӯBeanй»ҳи®ӨдҪңз”ЁеҹҹдёәsingletonеҚ•дҫӢ\n- **е·ҘеҺӮжЁЎејҸ**пјҡBeanFactoryгҖҒFactoryBeanз»ҹдёҖиҙҹиҙЈBeanеҜ№иұЎеҲӣе»ә\n- **д»ЈзҗҶжЁЎејҸ**пјҡAOPеә•еұӮдҪҝз”ЁJDKеҠЁжҖҒд»ЈзҗҶ / CGLibд»ЈзҗҶе®һзҺ°еҲҮйқўеўһејә\n- **йҖӮй…ҚеҷЁжЁЎејҸ**пјҡSpringMVCзҡ„HandlerAdapterйҖӮй…ҚеӨҡз§Қзұ»еһӢController\n\n## дёҡеҠЎејҖеҸ‘еҜ№еә”еңәжҷҜ\n- ж–Үд»¶дёҠдј ж”ҜжҢҒжң¬ең°гҖҒOSSгҖҒеӨҡеӯҳеӮЁеҲҮжҚў вҶ’ **зӯ–з•ҘжЁЎејҸ**\n- и®ўеҚ•ж”Ҝд»ҳжҲҗеҠҹеҗҺжҺЁйҖҒзҹӯдҝЎгҖҒз§ҜеҲҶгҖҒж¶ҲжҒҜйҖҡзҹҘ вҶ’ **и§ӮеҜҹиҖ…жЁЎејҸ**\n- е…ЁеұҖе…ұз”ЁзәҝзЁӢжұ гҖҒе…ЁеұҖе·Ҙе…·з®ЎзҗҶзұ» вҶ’ **еҚ•дҫӢжЁЎејҸ**','2026-06-13 23:43:32','2026-06-15 17:26:09','admin','admin'),(4,4,'# йӣҶеҗҲдёҺж•°з»„\nж•°з»„пјҡй•ҝеәҰеӣәе®ҡпјҢеҸӘиғҪеӯҳж”ҫеҗҢдёҖз§Қж•°жҚ®зұ»еһӢ\nйӣҶеҗҲпјҡй•ҝеәҰеҠЁжҖҒеҸҜеҸҳпјҢеҸҜеӯҳж”ҫд»»ж„Ҹеј•з”Ёзұ»еһӢеҜ№иұЎ\n\n# ListгҖҒSetгҖҒMap ж ёеҝғеҢәеҲ«\n